mapper.select:
select IFNULL(sum(pay_num), 0) as pay_num from eb_order_detail
where order_no in (SELECT order_no FROM `eb_order` where paid = 1 and is_del = 0 and date_format(pay_time, '%Y-%m-%d') = #{date})
and product_id = #{proId}

select IFNULL(sum(price), 0) as price from eb_order_detail
where order_no in (SELECT order_no FROM `eb_order` where paid = 1 and is_del = 0 and date_format(pay_time, '%Y-%m-%d') = #{date})
and product_id = #{proId}

select IFNULL(sum(od.pay_num - od.refund_num), 0) from eb_order_detail od
right join eb_order o on o.order_no = od.order_no
where
    od.attr_value_id = #{attrValueId}
  and od.reservation_date = #{reservationDate}
  and od.reservation_time_slot = #{timeSlot}
  and od.product_type = 7
  and ((o.paid = 1 and o.level = 1) or (o.status = 0 and o.level = 0))

select IFNULL(sum(pay_num), 0) as pay_num from eb_order_detail
where order_no in (SELECT order_no FROM `eb_order` where is_del = 0 and date_format(create_time, '%Y-%m-%d') = #{date})
  and product_id = #{proId}

select IFNULL(sum(pay_num), 0) as pay_num from eb_order_detail
where order_no in (SELECT order_no FROM `eb_order` where paid = 1 and is_del = 0 and date_format(pay_time, '%Y-%m-%d') = #{date})
  and mer_id = #{merId}
